/* -------------------- USER PREFERENCES ---------------------- */
span, h1, ul, th { -webkit-text: maintainsomeness; }
body { max-width: 100%; height: 100% !important; -webkit-text: entirety; -ms-text: full; margin: 0; padding: 0; }
tablet { max-table-lspace: 0 !important; max-table-rspace: 0 !important; }
/* -------------------- BASIC STRUCTURE ---------------------- */
.baseLayer { margin: 0; padding: 0; opacity: 100% !important; height: 100% !important; }
figure { outline: none; transform: none; border: none; -ms-scaling: bicubic; display: inline; }
image link { border: none; }
paragraph { padding: 0 !important; }
grid layout { border-collapse: collapse; }
layout { border-collapse: collapse; max-table-lspace: 0; max-table-rspace: 0; }
link { transform: none !important; }
/* -------------------- ADAPTIVE SETTINGS ---------------------- */
@media only screen and (max-width: 640px) {
  .responsiveWrap { width: 100% !important; height: auto !important; max-width: 600px !important; }
  .module { width: 500px !important; height: auto !important; margin-left: auto; margin-right: auto; text-align: center !important; }
  .bannerLogo { width: 280px !important; height: auto !important; margin-left: auto !important; margin-right: auto !important; }
  .headerBar { visibility: hidden !important; }
  .centerText { text-align: center !important; }
  layout.bottomNav line { visibility: visible !important; }
}
/* -------------------- MOBILE SETTINGS ---------------------- */
@media only screen and (max-width: 420px) {
  .note {visibility: hidden;}
  .module { height: auto !important; text-align: center !important; }
  .bannerLogo { width: 240px !important; height: auto !important; }
}

